        data-y={cell.y}
        data-glyph={cell.glyph}
        data-terrain={cell.terrain}
        data-fog={cell.fog}
        data-layer={cell.layer}
        data-feature-kind={cell.featureKind}
        data-feature-id={cell.featureId}
        data-has-item={cell.hasItem ? "true" : "false"}
        data-label={cell.label}
        data-shape={cell.shape}
        data-hit-flash={cell.hitFlash ? "true" : "false"}
        data-motion={cell.motion === null ? "none" : "arrive"}
        style={style}
      >
        <span className={styles.glyph} aria-hidden="true">
          {cell.glyph === " " ? "\u00a0" : cell.glyph}
        </span>
        {cell.badge.length > 0 ? (
          <span className={styles.badge} aria-hidden="true">
            {cell.badge}
          </span>
        ) : null}
        {cell.markers.map((marker) => (
          <span
            className={[
              styles.marker,
              marker.tone === "quest" ? styles.questMarker : "",
            ]
