 70	export async function driveRunToWin(page: Page): Promise<void> {
 71	  const state = page.getByTestId("game-state");
 72	  const visitedByDepth = new Map<number, Set<string>>();
 73	  let turns = 0;
 74	  let lastSignature = "";
 75	  let stuckRepeats = 0;
 76	
 77	  while (turns < MAX_TURN_CAP) {
 78	    await settleUi(page);
 79	
 80	    const shell = await readShellSnapshot(state);
 81	    if (shell.screen !== "playing") {
 82	      if (shell.terminalStatus === "WIN") {
 83	        return;
 84	      }
 85	      await dumpStuckState(page, "left playing screen before WIN");
 86	      throw new BotFailure("left playing screen before WIN", {
 87	        shell,
 88	        hud: await readHudSnapshot(page),
 89	        player: null,
 90	        gameStateAttributes: await readGameStateAttributes(page),
 91	        recentLogLines: await readRecentLogLines(page),
 92	        reason: `screen=${shell.screen} terminal=${shell.terminalStatus}`,
 93	      });
 94	    }
 95	
 96	    if (shell.terminalStatus === "WIN") {
 97	      return;
 98	    }
 99	
100	    const beforeTurn = shell.turn;
101	    const key = await choosePolicyKey(page, shell, visitedByDepth);
102	    if (key === null) {
103	      await waitForUiFrame(page);
104	    } else {
105	      await pressGameplayKey(page, key);
106	    }
107	
108	    const after = await readShellSnapshot(state);
109	    if (after.turn === beforeTurn && after.screen === "playing") {
110	      const signature = await progressSignature(page, after);
111	      stuckRepeats = signature === lastSignature ? stuckRepeats + 1 : 0;
112	      lastSignature = signature;
113	      if (stuckRepeats >= 24) {
114	        await dumpStuckState(page, "no turn progress for 24 identical states");
115	        throw new Error("bot stuck: no turn progress");
116	      }
117	      continue;
118	    }
119	
120	    stuckRepeats = 0;
121	    lastSignature = "";
122	    turns += 1;
123	  }
124	
125	  await dumpStuckState(page, `turn cap ${MAX_TURN_CAP} exceeded`);
126	  throw new Error(`bot exceeded turn cap (${MAX_TURN_CAP})`);
127	}
