238	
239	  if (hud !== null && hud.hpRatio <= 0.45) {
240	    const healed = await tryHeal(page);
241	    if (healed) {
242	      return null;
243	    }
244	  }
245	
246	  if (shell.depth >= FINAL_DEPTH) {
247	    if (isOnHoard(cells, player)) {
