253	      (cell) => cell.featureKind === "hoard",
254	    );
255	    const hoardRoute = greedyStep(
256	      player,
257	      hoard,
258	      cells,
259	      visitedByDepth.get(shell.depth),
260	    );
261	    if (hoardRoute !== null) {
262	      return hoardRoute;
263	    }
264	  }
265	
266	  if (isOnStairs(cells, player)) {
267	    return ">";
268	  }
269	
270	  const stairs = findTargetCells(
271	    cells,
272	    (cell) => cell.glyph === ">" || cell.terrain === "stairs_down",
273	  );
274	  const stairsRoute = greedyStep(player, stairs, cells, visitedByDepth.get(shell.depth));
275	  if (stairsRoute !== null) {
