114	  options: BotOptions = {}
115	): Promise<void> {
116	  const state = page.getByTestId("game-state");
117	  const policyState: BotPolicyState = {
118	    visitedByDepth: new Map<number, Set<string>>(),
119	    rng: seededRandom(options.seed ?? resolveCampaignSeed()),
120	    log: options.log ?? console.log,
121	    lastMoveDirection: null
122	  };
123	  let turns = 0;
124	  let lastSignature = "";
125	  let stuckRepeats = 0;
126	  let unchangedPositionTurns = 0;
127	
128	  while (turns < MAX_TURN_CAP) {
129	    await settleUi(page);
130	
131	    const shell = await readShellSnapshot(state);
132	    if (shell.screen !== "playing") {
133	      if (shell.terminalStatus === "WIN") {
134	        return;
135	      }
136	      await dumpStuckState(page, "left playing screen before WIN");
137	      throw new BotFailure("left playing screen before WIN", {
138	        shell,
139	        hud: await readHudSnapshot(page),
140	        player: null,
141	        gameStateAttributes: await readGameStateAttributes(page),
142	        recentLogLines: await readRecentLogLines(page),
143	        reason: `screen=${shell.screen} terminal=${shell.terminalStatus}`
144	      });
145	    }
146	
147	    if (shell.terminalStatus === "WIN") {
148	      return;
149	    }
150	
151	    const beforeTurn = shell.turn;
152	    const beforePosition = await readPlayerPosition(page);
153	    const key = await choosePolicyKey(page, shell, policyState);
154	    const keyDirection = directionForKey(key);
155	    if (key === null) {
156	      await waitForUiFrame(page);
157	    } else {
158	      await pressGameplayKey(page, key);
159	    }
160	
161	    const after = await readShellSnapshot(state);
162	    if (after.turn === beforeTurn && after.screen === "playing") {
163	      const signature = await progressSignature(page, after);
164	      stuckRepeats = signature === lastSignature ? stuckRepeats + 1 : 0;
165	      lastSignature = signature;
166	      if (stuckRepeats >= NO_PROGRESS_REPEAT_CAP) {
167	        await dumpStuckState(
168	          page,
169	          `no turn progress for ${NO_PROGRESS_REPEAT_CAP} identical states`
170	        );
171	        throw new Error("bot stuck: no turn progress");
172	      }
173	      continue;
174	    }
175	
176	    stuckRepeats = 0;
177	    lastSignature = "";
178	    turns += 1;
179	    if (keyDirection !== null) {
180	      policyState.lastMoveDirection = keyDirection;
181	    }
182	
183	    const afterPosition = await readPlayerPosition(page);
184	    unchangedPositionTurns =
185	      beforePosition !== null &&
186	      afterPosition !== null &&
187	      samePosition(beforePosition, afterPosition)
188	        ? unchangedPositionTurns + 1
189	        : 0;
190	
191	    if (
192	      unchangedPositionTurns >= PINNED_POSITION_TURNS &&
193	      afterPosition !== null &&
194	      after.screen === "playing"
195	    ) {
196	      await breakPinnedLoop(page, after, afterPosition, policyState);
197	      unchangedPositionTurns = 0;
198	    }
199	
200	    if (turns % TELEMETRY_INTERVAL_TURNS === 0) {
201	      await logTelemetry(page, after, policyState);
202	    }
203	  }
204	
205	  const shell = await readShellSnapshot(state);
206	  await dumpStuckState(
207	    page,
208	    `turn cap ${MAX_TURN_CAP} exceeded at depth ${shell.depth}`
209	  );
210	  throw new Error(
211	    `bot exceeded turn cap (${MAX_TURN_CAP}) at depth ${shell.depth}`
212	  );
213	}
