793	function bfsRoute(
794	  start: GridPosition,
795	  targets: readonly GridPosition[],
796	  walkable: ReadonlySet<string>
797	): GridPosition[] | null {
798	  const targetKeys = new Set(
799	    targets.map((target) => posKey(target.x, target.y))
800	  );
801	  return bfsRouteToPredicate(start, walkable, (position) =>
802	    targetKeys.has(posKey(position.x, position.y))
803	  );
804	}
