806	function bfsRouteToPredicate(
807	  start: GridPosition,
808	  walkable: ReadonlySet<string>,
809	  target: (position: GridPosition) => boolean
810	): GridPosition[] | null {
811	  if (target(start)) {
812	    return [start];
813	  }
814	
815	  const queue: GridPosition[][] = [[start]];
816	  const seen = new Set([posKey(start.x, start.y)]);
817	
818	  while (queue.length > 0) {
819	    const route = queue.shift();
820	    if (route === undefined) {
821	      break;
822	    }
823	
824	    const current = route[route.length - 1];
825	    if (current === undefined) {
826	      continue;
827	    }
828	
829	    for (const neighbor of neighbors(current)) {
830	      const key = posKey(neighbor.x, neighbor.y);
831	      if (seen.has(key) || !walkable.has(key)) {
832	        continue;
833	      }
834	
835	      const nextRoute = [...route, neighbor];
836	      if (target(neighbor)) {
837	        return nextRoute;
838	      }
839	
840	      seen.add(key);
841	      queue.push(nextRoute);
842	    }
843	  }
844	
845	  return null;
846	}
